namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post.")
        ]);
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Id > lastSeenId).ToList());
        }
    }

    /// <summary>Simulates an external system pushing a new notification periodically.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Server health check passed.",
            "Deployment completed.",
            "New user signed up.",
            "Disk usage alert cleared.",
            "Backup finished successfully."
        };

        lock (_lock)
        {
            var msg = messages[(_nextId - 1) % messages.Length];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
    {
        var id = _nextId++;
        return new Notification(id, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <span class="badge bg-primary rounded-pill mb-3 fs-6">
        @notifications.Count notification@(notifications.Count != 1 ? "s" : "")
    </span>

    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification>? notifications;
    private CancellationTokenSource? cts;

    // Persisted across prerender → interactive so we don't re-fetch.
    [PersistentState]
    public int[]? PersistedIds { get; set; }

    [PersistentState]
    public string[]? PersistedMessages { get; set; }

    [PersistentState]
    public DateTime[]? PersistedTimestamps { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore from persisted state if available (interactive re-render).
        if (PersistedIds is not null && PersistedMessages is not null && PersistedTimestamps is not null)
        {
            notifications = PersistedIds
                .Select((id, i) => new BlazorNotifications.Services.Notification(
                    id, PersistedMessages[i], PersistedTimestamps[i]))
                .ToList();
        }
        else
        {
            // First load (prerender). Fetch from service and persist.
            notifications = await NotificationService.GetNotificationsAsync();
            PersistedIds = notifications.Select(n => n.Id).ToArray();
            PersistedMessages = notifications.Select(n => n.Message).ToArray();
            PersistedTimestamps = notifications.Select(n => n.Timestamp).ToArray();
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs when the page is truly interactive — never during prerender.
            cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                // Simulate an external notification arriving.
                NotificationService.SimulateIncoming();

                var lastId = notifications?.LastOrDefault()?.Id ?? 0;
                var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

                if (newer.Count > 0)
                {
                    notifications ??= [];
                    notifications.AddRange(newer);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        cts?.Cancel();
        cts?.Dispose();
    }
}

