namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            CreateNotification("Welcome to the notification center!"),
            CreateNotification("Your profile was updated successfully."),
            CreateNotification("New comment on your post.")
        ]);
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Id > lastSeenId).ToList());
        }
    }

    /// <summary>Simulates an external system pushing a new notification periodically.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Server health check passed.",
            "Deployment completed.",
            "New user signed up.",
            "Disk usage alert cleared.",
            "Backup finished successfully."
        };

        lock (_lock)
        {
            var msg = messages[(_nextId - 1) % messages.Length];
            _notifications.Add(CreateNotification(msg));
        }
    }

    private Notification CreateNotification(string message)
    {
        var id = _nextId++;
        return new Notification(id, message, DateTime.UtcNow);
    }
}

